  "business_expectations": [
    {
      "expectation_id": "意图分类为客户画像",
      "downstream_consumer": "营销规划下游模块",
      "user_intent": "了解购买重疾险的客户特征",
      "expected_outcome": "意图标签为 customer_portrait，置信度较高",
      "required_capabilities": [
        "意图识别"
      ],
      "acceptance_criteria": [
        "intent 必须为 'customer_portrait'",
        "confidence 应 >= 0.8"
      ],
      "boundary": {
        "scope": "单轮意图识别"
      },
      "priority": "高",
      "evidence_refs": []
    },
    {
      "expectation_id": "实体提取为重疾险",
      "downstream_consumer": "客户画像分析模块",
      "user_intent": "指定产品为 '重疾险'",
      "expected_outcome": "target_value 为 '重疾险'",
      "required_capabilities": [
        "实体提取"
      ],
      "acceptance_criteria": [
        "target_value 必须为 '重疾险'"
      ],
      "boundary": {},
      "priority": "高",
      "evidence_refs": []
    }
  ],
  "fulfillment_assessments": [
    {
      "expectation_id": "意图分类为客户画像",
      "status": "not_fulfilled",
      "score": 0,
      "expected_evidence": [
        "intent: customer_portrait",
        "confidence >= 0.8"
      ],
      "actual_evidence": [
        "intent: other",
        "confidence: 0.5"
      ],
      "downstream_impact": "下游无法正确执行客户画像分析流程",
      "blocking": true,
      "confidence": 1.0,
      "evidence_refs": [
        {
          "source": "extracted_output"
        }
      ]
    },
    {
      "expectation_id": "实体提取为重疾险",
      "status": "not_fulfilled",
      "score": 0,
      "expected_evidence": [
        "target_value: '重疾险'"
      ],
      "actual_evidence": [
        "target_value: null"
      ],
      "downstream_impact": "缺少关键分析维度，导致分析失败",
      "blocking": true,
      "confidence": 1.0,
      "evidence_refs": [
        {
          "source": "extracted_output"
        }
      ]
    }
  ],
  "overall_fulfillment": {
    "status": "not_fulfilled",
    "summary": "意图识别输出为 other，完全未满足客户画像意图和实体提取要求，置信度低，严重影响下游功能。"
  },
  "expected": {
    "intent": "customer_portrait",
    "target_value": "重疾险",
    "confidence_min": 0.8
  },
  "missing": [
    {
      "kind": "intent_label",
      "error_type": "classification_error",
      "expected": "customer_portrait",
      "actual": "other",
      "evidence_ref": "adapter_extraction",
      "raw": {},
      "incomplete": false
    },
    {
      "kind": "entity_value",
      "error_type": "extraction_failure",
      "expected": "重疾险",
      "actual": null,
      "evidence_ref": "adapter_extraction",
      "raw": {},
      "incomplete": false
    }
  ],
  "wrong": [
    {
      "kind": "intent_label",
      "error_type": "incorrect_value",
      "expected": "customer_portrait",
      "actual": "other",
      "evidence_ref": "adapter_extraction",
      "raw": {},
      "incomplete": false
    },
    {
      "kind": "confidence",
      "error_type": "below_threshold",
      "expected": 0.8,
      "actual": 0.5,
      "evidence_ref": "adapter_extraction",
      "raw": {},
      "incomplete": false
    }
  ],
  "extra": [
    {
      "kind": "sub_intent_label",
      "error_type": "unnecessary_output",
      "expected": null,
      "actual": {
        "subIntent": "其他意图"
      },
      "evidence_ref": "subIntent_field",
      "raw": {},
      "incomplete": false
    }
  ],
  "evidence": [
    {
      "source": "extracted_output",
      "content": {
        "intent": "other",
        "confidence": 0.5,
        "target_value": null
      }
    },
    {
      "source": "reference_contract",
      "content": {
        "intent": "customer_portrait",
        "confidence": 0.95,
        "target_value": "重疾险"
      }
    }
  ],
  "reasoning_summary": "用户查询意图为分析购买重疾险的客户画像，期望意图为 customer_portrait，目标实体为重疾险。实际系统输出意图为 other（其他意图），置信度仅 0.5，目标值为空，完全未满足业务需求。下游模块无法基于该结果进行客户画像分析，存在阻断性错误。"
}

